const input = $input.first().json;
const outputText = input.output || '';

let jsonResult = null;

const jsonMatch = outputText.match(/```json\s*([\s\S]*?)\s*```/);
if (jsonMatch && jsonMatch[1]) {
    try {
        jsonResult = JSON.parse(jsonMatch[1].trim());
    } catch (e) {
        console.log('Error parseando JSON:', e);
    }
}

if (!jsonResult) {
    const objectMatch = outputText.match(/\{[\s\S]*\}/);
    if (objectMatch) {
        try {
            jsonResult = JSON.parse(objectMatch[0]);
        } catch (e) {
            console.log('Error parseando objeto:', e);
        }
    }
}

if (!jsonResult) {
    return [{
        json: {
            output: {
                error: 'No se pudo extraer JSON válido',
                raw_output: outputText
            }
        }
    }];
}

const resultadoLimpio = {
    status: jsonResult.status || 'unknown',
    file_name: jsonResult.file_name || '',
    content: jsonResult.content || '',
    changes: jsonResult.changes || [],
    suggested_errors: jsonResult.suggested_errors || []
};

if (jsonResult.suggested_errors && jsonResult.suggested_errors.length > 0) {
    resultadoLimpio.status = jsonResult.status || 'needs_revision';
}

return [{
    json: {
        output: resultadoLimpio
    }
}];

